const int MOD = 1e9 + 7;

long long solve(std::vector<std::vector<long long>> points) {
    map<long long, vector<long long>> y_to_x;
    for (const auto& point : points) {
        long long x = point[0];
        long long y = point[1];
        y_to_x[y].push_back(x);
    }

    long long res = 0;
    for (auto& [y1, x_list1] : y_to_x) {
        if (x_list1.size() < 2) continue;
        sort(x_list1.begin(), x_list1.end());
        for (auto& [y2, x_list2] : y_to_x) {
            if (y2 <= y1) continue;
            if (x_list2.size() < 2) continue;
            sort(x_list2.begin(), x_list2.end());

            int i = 0, j = 0;
            long long cnt = 0;
            int n = x_list1.size(), m = x_list2.size();
            while (i < n && j < m) {
                if (x_list1[i] == x_list2[j]) {
                    cnt++;
                    i++;
                    j++;
                } else if (x_list1[i] < x_list2[j]) {
                    i++;
                } else {
                    j++;
                }
            }
            long long c = (x_list1.size() - cnt) * (x_list2.size() - cnt) + cnt * (cnt - 1);
            res += c;
            res %= MOD;
        }
    }
    return res;
}

